    """2D primitives for deterministic server-side plan previews."""

    warnings: list[dict[str, Any]] = []

    def span_in_vertical_range(z0: float, z1: float) -> bool:
        if view_range_clip_mm is None:
            return True
        lo, hi, _cut = view_range_clip_mm
        return _closed_z_intervals_overlap_mm(z0, z1, lo, hi)

    crop_box = crop_box_mm
    if pinned_pv_el is not None:
        cmn, cmx = pinned_pv_el.crop_min_mm, pinned_pv_el.crop_max_mm
        has_partial_crop = (cmn is not None) ^ (cmx is not None)
        if has_partial_crop:
            warnings.append(
                {
                    "code": "cropBoxNotApplied",
                    "message": "Plan viewport crop requires both cropMinMm and cropMaxMm; primitives are not cropped.",
                }
            )
        if _plan_view_range_authoring_incomplete(pinned_pv_el):
            warnings.append(
                {
                    "code": "viewRangeNotApplied",
                    "message": "Plan view range is incomplete (both viewRangeBottomMm and viewRangeTopMm are required for vertical filtering); vertical clip is not applied.",
                }
            )

    walls: list[dict[str, Any]] = []
    floors: list[dict[str, Any]] = []
    rooms: list[dict[str, Any]] = []
    doors: list[dict[str, Any]] = []
    windows: list[dict[str, Any]] = []
    stairs: list[dict[str, Any]] = []
    roofs: list[dict[str, Any]] = []
    grid_lines: list[dict[str, Any]] = []
    room_separations: list[dict[str, Any]] = []
    dimensions: list[dict[str, Any]] = []

    def cat_eff(key: str) -> tuple[float, str]:
        if category_resolved is None:
            if key == "room_separation":
                return (1.0, "dash_short")
            return (1.0, "solid")
        r = category_resolved[key]
        return (r.line_weight_factor, r.line_pattern_token)

    def lvl_ok(lv: str | None) -> bool:
        if not level:
            return True
        return lv == level if lv else False

    for eid in sorted(doc.elements.keys()):
        e = doc.elements[eid]

        if isinstance(e, WallElem):
            if "wall" in hidden_semantic or not lvl_ok(e.level_id):
                continue
            if crop_box is not None and not _segment_intersects_crop_xy(
                e.start.x_mm, e.start.y_mm, e.end.x_mm, e.end.y_mm, crop_box
            ):
                continue

def _wall_corner_join_summary_for_plan_view(
    doc: Document,
    *,
    level: str | None,
    hidden_semantic: set[str],
    crop_box_mm: tuple[float, float, float, float] | None,
    view_range_clip_mm: tuple[float, float, float] | None,
) -> dict[str, Any] | None:
    """Corner/overlap join rows filtered like wall-opening cut-fidelity visibility gates."""

    full = collect_wall_corner_join_summary_v1(doc)
    if not full:
        return None
    raw_joins = full.get("joins")
    if not isinstance(raw_joins, list):
        return None

    def span_in_vertical_range(z0: float, z1: float) -> bool:
        if view_range_clip_mm is None:
            return True
        lo, hi, _cut = view_range_clip_mm
        return _closed_z_intervals_overlap_mm(z0, z1, lo, hi)

    def lvl_ok(lv: str | None) -> bool:
        if not level:
            return True
        return lv == level if lv else False

    def opening_visible(oid: str) -> bool:
        e = doc.elements.get(oid)
        if isinstance(e, DoorElem):
            w = doc.elements.get(e.wall_id)
            if not isinstance(w, WallElem):
                return False
            if (
                "door" in hidden_semantic
                or "wall" in hidden_semantic
                or not lvl_ok(w.level_id)
            ):
                return False
            cx_mm, cy_mm = _hosted_xy_mm_on_wall(e, w)
            crop_box = crop_box_mm
            if crop_box is not None:
                opening_ok = _point_in_crop_xy(cx_mm, cy_mm, crop_box) or _segment_intersects_crop_xy(
                    w.start.x_mm, w.start.y_mm, w.end.x_mm, w.end.y_mm, crop_box
                )
                if not opening_ok:
                    return False
            dwz0, dwz1 = _wall_vertical_span_mm(doc, w)
            return span_in_vertical_range(dwz0, dwz1)
        if isinstance(e, WindowElem):
            w = doc.elements.get(e.wall_id)
            if not isinstance(w, WallElem):
                return False
            if (
                "window" in hidden_semantic
                or "wall" in hidden_semantic
                or not lvl_ok(w.level_id)
            ):
                return False
            cx_mm, cy_mm = _hosted_xy_mm_on_wall(e, w)
            crop_box = crop_box_mm
            if crop_box is not None:
                opening_ok = _point_in_crop_xy(cx_mm, cy_mm, crop_box) or _segment_intersects_crop_xy(
                    w.start.x_mm, w.start.y_mm, w.end.x_mm, w.end.y_mm, crop_box
                )
                if not opening_ok:
                    return False
            wwz0, wwz1 = _wall_vertical_span_mm(doc, w)
            return span_in_vertical_range(wwz0, wwz1)
        return False

    out_joins: list[dict[str, Any]] = []
    for row in raw_joins:
        if not isinstance(row, dict):
            continue
        lvl_id = row.get("levelId")
        if level and str(lvl_id or "") != level:
            continue
        vm = row.get("vertexMm")
        if not isinstance(vm, dict):
            continue
        try:
            vx = float(vm["xMm"])
            vy = float(vm["yMm"])
        except (KeyError, TypeError, ValueError):
            continue
        if crop_box_mm is not None and not _point_in_crop_xy(vx, vy, crop_box_mm):
            continue
        oids = row.get("affectedOpeningIds")
        if not isinstance(oids, list):
            oids = []
        filtered = sorted(str(x) for x in oids if opening_visible(str(x)))
        new_row = dict(row)
        new_row["affectedOpeningIds"] = filtered
        out_joins.append(new_row)

    if not out_joins:
        return None
    return {"format": "wallCornerJoinSummary_v1", "joins": out_joins}

"""Deterministic wall corner join evidence for exchange manifests (WP-B02 / WP-X02).

``collect_wall_corner_join_evidence_v0`` documents axis-aligned L-corner topology only.
``collect_wall_corner_join_summary_v1`` adds richer join classification without changing v0 rows.
"""

from __future__ import annotations

import math
from typing import Any

from bim_ai.document import Document
from bim_ai.elements import DoorElem, WallElem, WindowElem
from bim_ai.opening_cut_primitives import hosted_opening_half_span_mm, wall_plan_axis_aligned_xy

# Extra plan clearance beyond reveal-expanded half-width + half wall thickness for L-corner band.
CORNER_JOIN_BAND_CLEARANCE_MM = 150.0

_EPS_MM = 1e-3
_PARALLEL_DOT = 0.95
_PERP_DOT = 0.05


def _endpoints_rounded_mm(w: WallElem, eps_mm: float = 1.0) -> set[tuple[float, float]]:
    return {
        (round(w.start.x_mm / eps_mm) * eps_mm, round(w.start.y_mm / eps_mm) * eps_mm),
        (round(w.end.x_mm / eps_mm) * eps_mm, round(w.end.y_mm / eps_mm) * eps_mm),
    }


def _wall_unit_xy(w: WallElem) -> tuple[float, float] | None:
    dx = float(w.end.x_mm - w.start.x_mm)
    dy = float(w.end.y_mm - w.start.y_mm)
    span = math.hypot(dx, dy)
    if span < 1e-3:
        return None
    return dx / span, dy / span


def _hosted_anchor_xy_mm(opening: DoorElem | WindowElem, wall: WallElem) -> tuple[float, float]:
    sx, sy = float(wall.start.x_mm), float(wall.start.y_mm)
    dx = float(wall.end.x_mm) - sx
    dy = float(wall.end.y_mm) - sy
    length_mm = max(_EPS_MM, math.hypot(dx, dy))
    ux, uy = dx / length_mm, dy / length_mm
    return sx + ux * float(opening.along_t) * length_mm, sy + uy * float(opening.along_t) * length_mm


def _corner_join_id(level_id: str, vx: float, vy: float, w0: str, w1: str) -> str:
    return f"join:{level_id}:{vx}:{vy}:{w0}:{w1}"


def _overlap_join_id(
    level_id: str,
    w0: str,
    w1: str,
    *,
    axis_key: str,
    anchor: float,
    lo: float,
    hi: float,
) -> str:
    return (
        f"joinOv:{level_id}:{w0}:{w1}:{axis_key}:"
        f"{round(float(anchor), 3)}:{round(float(lo), 3)}:{round(float(hi), 3)}"
    )


def _plan_token_for_kind(kind: str) -> str:
    return {
        "butt": "WJ_BUTT_AA",
        "miter_candidate": "WJ_MITER_CAND",
        "unsupported_skew": "WJ_UNSUPPORTED_SKEW",
        "proxy_overlap": "WJ_PROXY_OVERLAP",
    }[kind]


def _aa_wall_dom_axis_interval(w: WallElem) -> tuple[str, float, float, float] | None:
    """Axis-aligned wall as overlap interval on the dominant axis."""

    if not wall_plan_axis_aligned_xy(w):
        return None
    x0, y0 = float(w.start.x_mm), float(w.start.y_mm)
    x1, y1 = float(w.end.x_mm), float(w.end.y_mm)
    if abs(y1 - y0) <= _EPS_MM:
        return ("h", (y0 + y1) * 0.5, min(x0, x1), max(x0, x1))
    if abs(x1 - x0) <= _EPS_MM:
        return ("v", (x0 + x1) * 0.5, min(y0, y1), max(y0, y1))
    return None


def _collect_affected_opening_ids_corner(
    doc: Document,
    *,
    wall_a: WallElem,
    wall_b: WallElem,
    vx: float,
    vy: float,
) -> list[str]:
    walls = {wall_a.id, wall_b.id}
    out: list[str] = []
    for eid in sorted(doc.elements.keys()):
        e = doc.elements[eid]
        if not isinstance(e, (DoorElem, WindowElem)):
            continue
        if e.wall_id not in walls:
            continue
        w = doc.elements.get(e.wall_id)
        if not isinstance(w, WallElem):
            continue

overlap_tol_mm2 = 120.0
for lw in walls_by_level.values():
    n = len(lw)
    for i in range(n):
        for j in range(i + 1, n):
            a = lw[i]
            b = lw[j]
            pa = wall_corners(
                (a.start.x_mm, a.start.y_mm),
                (a.end.x_mm, a.end.y_mm),
                a.thickness_mm,
            )
            pb = wall_corners(
                (b.start.x_mm, b.start.y_mm),
                (b.end.x_mm, b.end.y_mm),
                b.thickness_mm,
            )
            if not sat_overlap(pa, pb):
                continue
            # Skip mitre/T junction clashes where centerlines touch at a single elbow.
            if _wall_corner_or_t_overlap_exempt(a, b):
