80	} {
81	  let minX = Number.POSITIVE_INFINITY;
82	  let maxX = Number.NEGATIVE_INFINITY;
83	  let minZ = Number.POSITIVE_INFINITY;
84	  let maxZ = Number.NEGATIVE_INFINITY;
85	  for (const p of poly) {
86	    minX = Math.min(minX, p.xMm);
87	
88	    maxX = Math.max(maxX, p.xMm);
89	
90	    minZ = Math.min(minZ, p.yMm);
91	
92	    maxZ = Math.max(maxZ, p.yMm);
93	  }
94	
95	  const spanX = Math.max(maxX - minX, 1);
96	
97	  const spanZ = Math.max(maxZ - minZ, 1);
98	
99	  return {
100	    minX,
101	
102	    maxX,
103	
104	    minZ,
105	
106	    maxZ,
107	
108	    cx: (minX + maxX) / 2,
109	
110	    cz: (minZ + maxZ) / 2,
111	
112	    spanX,
113	
114	    spanZ,
115	  };
116	}
117	
118	function elevationMForLevel(levelId: string, elementsById: Record<string, Element>): number {
119	  const lvl = elementsById[levelId];
120	  if (!lvl || lvl.kind !== 'level') return 0;
121	  return lvl.elevationMm / 1000;
122	}
123	
124	function hostedXZ(
125	  hosted: Extract<Element, { kind: 'door' } | { kind: 'window' }>,
126	  wall: WallElem,
127	): { px: number; pz: number } {
128	  const sx = wall.start.xMm / 1000;
129	  const sz = wall.start.yMm / 1000;
130	  const dx = wall.end.xMm / 1000 - sx;
131	  const dz = wall.end.yMm / 1000 - sz;
132	  const len = Math.max(1e-6, Math.hypot(dx, dz));
133	  const ux = dx / len;
134	  const uz = dz / len;
135	  return {
136	    px: sx + ux * hosted.alongT * len,
137	    pz: sz + uz * hosted.alongT * len,
138	  };
139	}
140	
141	function wallYaw(wall: WallElem) {
142	  const sx = wall.start.xMm / 1000;
143	  const sz = wall.start.yMm / 1000;
144	  const ex = wall.end.xMm / 1000;
145	  const ez = wall.end.yMm / 1000;
146	  return Math.atan2(ez - sz, ex - sx);
147	}
148	
149	function makeFloorSlabMesh(
150	  floor: Extract<Element, { kind: 'floor' }>,
151	  elementsById: Record<string, Element>,
152	  paint: ViewportPaintBundle | null,
153	): THREE.Mesh {
154	  const b = xzBoundsMm(floor.boundaryMm ?? []);
155	
156	  const elev = elevationMForLevel(floor.levelId, elementsById);
157	
158	  const th = THREE.MathUtils.clamp(floor.thicknessMm / 1000, 0.05, 1.8);
159	
160	  const mesh = new THREE.Mesh(
161	    new THREE.BoxGeometry(b.spanX / 1000, th, b.spanZ / 1000),
162	
163	    new THREE.MeshStandardMaterial({
164	      color: categoryColorOr(paint, 'floor'),
165	      roughness: paint?.categories.floor.roughness ?? 0.9,
166	      transparent: true,
167	      opacity: 0.92,
168	    }),
169	  );
170	
171	  mesh.position.set(b.cx / 1000, elev + th / 2, b.cz / 1000);
172	
173	  mesh.userData.bimPickId = floor.id;
174	
175	  return mesh;
176	}
177	
178	function makeRoofMassMesh(
