import {
  type CSSProperties,
  type FocusEvent,
  type JSX,
  type KeyboardEvent,
  type MouseEvent,
  useCallback,
  useId,
  useRef,
} from 'react';
import { Icons, IconLabels, ICON_SIZE, type LucideLikeIcon } from '@bim-ai/ui';

/**
 * TopBar — spec §11.
 *
 * Three regions:
 *   1. Left  (240 px): hamburger toggle, logo placeholder, project-name button.
 *   2. Center: mode pills traversable with arrow keys (`role="tablist"`).
 *   3. Right: command palette button, collaborators count, settings, theme
 *      toggle, avatar.
 *
 * The TopBar is purely presentational. State (current mode, theme,
 * collaborators) is owned by callers (Workspace + Mode-switching WP-D03).
 */

export const WORKSPACE_MODES = [
  { id: 'plan', label: 'Plan', hotkey: '1' },
  { id: '3d', label: '3D', hotkey: '2' },
  { id: 'plan-3d', label: 'Plan + 3D', hotkey: '3' },
  { id: 'section', label: 'Section', hotkey: '4' },
  { id: 'sheet', label: 'Sheet', hotkey: '5' },
  { id: 'schedule', label: 'Schedule', hotkey: '6' },
  { id: 'agent', label: 'Agent', hotkey: '7' },
] as const;

export type WorkspaceMode = (typeof WORKSPACE_MODES)[number]['id'];

export interface TopBarProps {
  mode: WorkspaceMode;
  onModeChange: (next: WorkspaceMode) => void;
  projectName: string;
  onProjectNameClick?: () => void;
  /** Forwarded to the project-name pill so external popovers can anchor. */
  projectNameRef?: React.RefObject<HTMLButtonElement | null>;
  onHamburgerClick?: () => void;
  theme: 'light' | 'dark';
  onThemeToggle?: () => void;
  onCommandPalette?: () => void;
  onSettings?: () => void;
  collaboratorsCount?: number;
  onCollaboratorsClick?: () => void;
  /** Identifier shown as the avatar fallback when no avatar URL is provided. */
  avatarInitials?: string;
  /** Presence peers to render as avatar chips (up to 6). */
  peers?: Array<{ name?: string; color?: string }>;
}

export function TopBar({
  mode,
  onModeChange,
  projectName,
  onProjectNameClick,
  projectNameRef,
  onHamburgerClick,
  theme,
  onThemeToggle,
  onCommandPalette,
  onSettings,
  collaboratorsCount,
  onCollaboratorsClick,
  avatarInitials,
  peers,
}: TopBarProps): JSX.Element {
  const tablistId = useId();
  return (
    <div
      data-testid="topbar"
      role="banner"
      style={topBarStyle}
      className="flex w-full items-center gap-4 border-b border-border bg-background px-4"
    >
      <TopBarLeft
        projectName={projectName}
        onProjectNameClick={onProjectNameClick}
        projectNameRef={projectNameRef}
        onHamburgerClick={onHamburgerClick}
      />
      <TopBarModePills tablistId={tablistId} mode={mode} onModeChange={onModeChange} />
      <TopBarRight
        theme={theme}
        onThemeToggle={onThemeToggle}
        onCommandPalette={onCommandPalette}
        onSettings={onSettings}
        collaboratorsCount={collaboratorsCount}
        onCollaboratorsClick={onCollaboratorsClick}
        avatarInitials={avatarInitials}
        peers={peers}
      />
    </div>
  );
}

const topBarStyle: CSSProperties = {
  height: 'var(--shell-topbar-height)',
  minHeight: 'var(--shell-topbar-height)',
};

function TopBarLeft({
  projectName,
  onProjectNameClick,
  projectNameRef,
  onHamburgerClick,
}: {
  projectName: string;
  onProjectNameClick?: () => void;
  projectNameRef?: React.RefObject<HTMLButtonElement | null>;
  onHamburgerClick?: () => void;
}): JSX.Element {
  return (
    <div className="flex items-center gap-3" style={{ minWidth: 240 }}>
      <IconButton Icon={Icons.hamburger} label={IconLabels.hamburger} onClick={onHamburgerClick} />
      <div
        aria-label="BIM AI"
        className="flex h-6 w-6 items-center justify-center rounded bg-accent text-accent-foreground"
        style={{ fontWeight: 700, fontSize: 11, letterSpacing: '0.01em' }}
      >
        BA
      </div>
      <button
        type="button"
        ref={projectNameRef}
        onClick={onProjectNameClick}
        className="flex items-center gap-1.5 rounded-md px-2 py-1 text-sm font-semibold text-foreground hover:bg-surface"
        aria-haspopup="menu"
        data-testid="topbar-project-name"
      >
        <span className="truncate" style={{ maxWidth: 160 }}>
          {projectName}
        </span>
        <Icons.disclosureOpen size={14} className="text-muted" aria-hidden="true" />
      </button>
    </div>
  );
}

function TopBarModePills({
  tablistId,
  mode,
  onModeChange,
}: {
  tablistId: string;
  mode: WorkspaceMode;
  onModeChange: (next: WorkspaceMode) => void;
}): JSX.Element {
  const tabRefs = useRef<Map<WorkspaceMode, HTMLButtonElement>>(new Map());
  const setTabRef = useCallback(
    (id: WorkspaceMode) => (el: HTMLButtonElement | null) => {
      if (el) tabRefs.current.set(id, el);
      else tabRefs.current.delete(id);
    },
    [],
  );

  const handleKey = useCallback(
    (event: KeyboardEvent<HTMLDivElement>) => {
      if (event.key !== 'ArrowRight' && event.key !== 'ArrowLeft') return;
      const idx = WORKSPACE_MODES.findIndex((m) => m.id === mode);
      if (idx < 0) return;
      const delta = event.key === 'ArrowRight' ? 1 : -1;
      const next = WORKSPACE_MODES[(idx + delta + WORKSPACE_MODES.length) % WORKSPACE_MODES.length];
      event.preventDefault();
      onModeChange(next.id);
      tabRefs.current.get(next.id)?.focus();
    },
    [mode, onModeChange],
  );

  return (
    <div
      role="tablist"
      id={tablistId}
      aria-label="Workspace modes"
      onKeyDown={handleKey}
      className="flex flex-1 items-center justify-center gap-1"
    >
      {WORKSPACE_MODES.map((m) => {
        const active = m.id === mode;
        return (
          <button
            key={m.id}
            ref={setTabRef(m.id)}
            type="button"
            role="tab"
            aria-selected={active}
            aria-keyshortcuts={m.hotkey}
            tabIndex={active ? 0 : -1}
            onClick={() => onModeChange(m.id)}
            data-active={active ? 'true' : 'false'}
            title={`${m.label} (${m.hotkey})`}
            className={[
              'relative rounded px-3 py-1.5 text-sm font-medium transition-colors',
              active
                ? 'text-accent'
                : 'text-muted hover:bg-surface hover:text-foreground',
            ].join(' ')}
            style={active ? { boxShadow: 'inset 0 -2px 0 0 var(--color-accent)' } : undefined}
          >
            {m.label}
            <span
              aria-hidden="true"
              className="ml-1.5 text-[10px] tabular-nums opacity-40"
            >
              {m.hotkey}
            </span>
          </button>
        );
      })}
    </div>
  );
}

function TopBarRight({
  theme,
  onThemeToggle,
  onCommandPalette,
  onSettings,
  collaboratorsCount,
  onCollaboratorsClick,
  avatarInitials,
  peers,
}: {
  theme: 'light' | 'dark';
  onThemeToggle?: () => void;
  onCommandPalette?: () => void;
  onSettings?: () => void;
  collaboratorsCount?: number;
  onCollaboratorsClick?: () => void;
  avatarInitials?: string;
  peers?: Array<{ name?: string; color?: string }>;
}): JSX.Element {
  return (
    <div className="flex items-center gap-2">
      <button
        type="button"
        onClick={onCommandPalette}
        aria-label={IconLabels.commandPalette}
        aria-keyshortcuts="Meta+K Control+K"
        className="flex items-center gap-1.5 rounded-md border border-border bg-surface px-2.5 py-1 text-xs font-medium text-muted shadow-sm hover:border-border hover:bg-surface-strong hover:text-foreground"
      >
        <Icons.commandPalette size={14} />
        <span>⌘K</span>
      </button>
      {peers && peers.length > 0 ? (
        <div
          data-testid="peer-avatars"
          className="flex items-center gap-0.5"
          aria-label="Active collaborators"
        >
          {peers.slice(0, 6).map((p, i) => (
            <div
              key={i}
              title={p.name ?? 'Anonymous'}
              className="flex h-6 w-6 items-center justify-center rounded-full border border-border text-[10px] font-medium text-foreground"
              style={{ backgroundColor: p.color ?? 'var(--color-surface-strong)' }}
            >
              {(p.name ?? '?').slice(0, 2).toUpperCase()}
            </div>
          ))}
        </div>
      ) : null}
      <IconButton
        Icon={Icons.collaborators}
        label={IconLabels.collaborators}
        onClick={onCollaboratorsClick}
        badge={collaboratorsCount}
      />
      <IconButton Icon={Icons.settings} label={IconLabels.settings} onClick={onSettings} />
      <IconButton
        Icon={theme === 'dark' ? Icons.themeLight : Icons.themeDark}
        label={theme === 'dark' ? IconLabels.themeLight : IconLabels.themeDark}
        onClick={onThemeToggle}
        data-testid="topbar-theme-toggle"
        data-current-theme={theme}
      />
      <div
        aria-label="Account"
        className="flex h-7 w-7 items-center justify-center rounded border border-border bg-surface font-medium text-xs text-foreground"
      >
        {(avatarInitials ?? '··').slice(0, 2)}
      </div>
    </div>
  );
}

interface IconButtonProps {
  Icon: LucideLikeIcon;
  label: string;
  onClick?: (e: MouseEvent<HTMLButtonElement>) => void;
  badge?: number;
  ['data-testid']?: string;
  ['data-current-theme']?: string;
}

function IconButton({
  Icon,
  label,
  onClick,
  badge,
  'data-testid': testId,
  'data-current-theme': currentTheme,
}: IconButtonProps): JSX.Element {
  const handleFocus = useCallback((_e: FocusEvent<HTMLButtonElement>) => {
    /* no-op — declared so consumers can extend later. */
  }, []);

  return (
    <button
      type="button"
      onClick={onClick}
      onFocus={handleFocus}
      aria-label={label}
      title={label}
      data-testid={testId}
      data-current-theme={currentTheme}
      className="relative inline-flex h-8 w-8 items-center justify-center rounded-md text-muted transition-colors hover:bg-surface hover:text-foreground"
    >
      <Icon size={ICON_SIZE.topbar} aria-hidden="true" />
      {typeof badge === 'number' && badge > 0 ? (
        <span
          data-testid="topbar-badge"
          aria-hidden="true"
          className="absolute -right-0.5 -top-0.5 inline-flex h-4 min-w-4 items-center justify-center rounded-pill bg-accent px-1 text-xs text-accent-foreground"
        >
          {badge}
        </span>
      ) : null}
    </button>
  );
}

import {
  type CSSProperties,
  type JSX,
  type KeyboardEvent,
  useCallback,
  useRef,
  useState,
} from 'react';
import { Icons, ICON_SIZE } from '@bim-ai/ui';
import {
  alignmentForPick,
  compassLabelFromAzimuth,
  type ViewCubeAlignment,
  type ViewCubeCorner,
  type ViewCubeFace,
  type ViewCubePick,
} from './viewCubeAlignment';

/**
 * ViewCube widget — spec §15.4.
 *
 * 96 × 96 px CSS-3D cube sitting top-right of the 3D canvas. Faces +
 * top corners are clickable (snap camera to that alignment). The cube
 * also supports drag-to-orbit: dragging anywhere on the stage orbits
 * the main camera live via the `onDrag` callback.
 *
 * The cube tracks the camera's full pose (azimuth + elevation) rather
 * than only azimuth, so it mirrors the scene orientation exactly.
 */

export interface ViewCubeProps {
  currentAzimuth: number;
  /** Camera elevation in radians (0 = horizontal, π/2 = straight down). */
  currentElevation: number;
  onPick: (pick: ViewCubePick, alignment: ViewCubeAlignment) => void;
  /** Raw pixel deltas during a drag. Viewport calls rig.orbit(dx, dy). */
  onDrag?: (dxPx: number, dyPx: number) => void;
  onHome?: () => void;
  /** Optional className for positioning. */
  className?: string;
}

const CUBE_SIZE_PX = 76;
const HALF = CUBE_SIZE_PX / 2;
const DRAG_THRESHOLD_PX = 4;

const TOP_CORNERS: { id: ViewCubeCorner; left: string; top: string }[] = [
  { id: 'TOP-NW', left: '6%', top: '6%' },
  { id: 'TOP-NE', left: '94%', top: '6%' },
  { id: 'TOP-SW', left: '6%', top: '94%' },
  { id: 'TOP-SE', left: '94%', top: '94%' },
];

interface FaceDef {
  id: ViewCubeFace;
  label: string;
  transform: string;
  /** Fraction of --color-foreground mixed into --color-surface (0–1). */
  shade: number;
}

const FACES: FaceDef[] = [
  { id: 'FRONT', label: 'FRONT', transform: `rotateY(0deg) translateZ(${HALF}px)`, shade: 0.04 },
  { id: 'BACK', label: 'BACK', transform: `rotateY(180deg) translateZ(${HALF}px)`, shade: 0.12 },
  { id: 'RIGHT', label: 'RIGHT', transform: `rotateY(90deg) translateZ(${HALF}px)`, shade: 0.08 },
  { id: 'LEFT', label: 'LEFT', transform: `rotateY(-90deg) translateZ(${HALF}px)`, shade: 0.08 },
  { id: 'TOP', label: 'TOP', transform: `rotateX(90deg) translateZ(${HALF}px)`, shade: 0.0 },
  {
    id: 'BOTTOM',
    label: 'BTM',
    transform: `rotateX(-90deg) translateZ(${HALF}px)`,
    shade: 0.22,
  },
];

export function ViewCube({
  currentAzimuth,
  currentElevation,
  onPick,
  onDrag,
  onHome,
  className,
}: ViewCubeProps): JSX.Element {
  const dragRef = useRef({ dragging: false, totalMoved: 0 });
  const suppressNextClickRef = useRef(false);
  const [isDragging, setIsDragging] = useState(false);
  const [isHovered, setIsHovered] = useState(false);

  function emit(pick: ViewCubePick): void {
    onPick(pick, alignmentForPick(pick));
  }

  function handleKey(event: KeyboardEvent<HTMLDivElement>): void {
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      emit({ kind: 'home' });
      onHome?.();
    }
  }

  const handlePointerDown = useCallback(
    (e: React.PointerEvent<HTMLDivElement>) => {
      if (e.button !== 0) return;
      dragRef.current = { dragging: true, totalMoved: 0 };
      setIsDragging(true);
      document.body.style.cursor = 'grabbing';

      const onMove = (ev: PointerEvent) => {
        const dx = ev.movementX;
        const dy = ev.movementY;
        dragRef.current.totalMoved += Math.abs(dx) + Math.abs(dy);
        onDrag?.(dx, dy);
      };

      const onUp = () => {
        if (dragRef.current.totalMoved > DRAG_THRESHOLD_PX) {
          suppressNextClickRef.current = true;
        }
        dragRef.current.dragging = false;
        setIsDragging(false);
        document.body.style.cursor = '';
        window.removeEventListener('pointermove', onMove);
        window.removeEventListener('pointerup', onUp);
      };

      window.addEventListener('pointermove', onMove);
      window.addEventListener('pointerup', onUp);
    },
    [onDrag],
  );

  const handleClickCapture = useCallback((e: React.MouseEvent) => {
    if (suppressNextClickRef.current) {
      e.stopPropagation();
      suppressNextClickRef.current = false;
    }
  }, []);

  // Cube orientation mirrors camera exactly: azimuth = horizontal rotation,
  // elevation = vertical tilt. The -elevation maps camera look-direction to
  // cube top-down rotation (elevation=0 → see front face, elevation=π/2 → see top face).
  const azimuthDeg = (-currentAzimuth * 180) / Math.PI;
  const elevationDeg = (currentElevation * 180) / Math.PI;

  const stageStyle: CSSProperties = {
    perspective: '320px',
    width: CUBE_SIZE_PX,
    height: CUBE_SIZE_PX,
    position: 'relative',
    cursor: isDragging ? 'grabbing' : 'grab',
  };

  const cubeStyle: CSSProperties = {
    position: 'absolute',
    inset: 0,
    transformStyle: 'preserve-3d',
    transform: `rotateX(${-elevationDeg}deg) rotateY(${azimuthDeg}deg)`,
    transition: isDragging ? 'none' : 'transform var(--motion-slow) var(--ease-snap)',
  };

  const showChrome = isHovered || isDragging;

  return (
    <div
      data-testid="view-cube"
      role="group"
      aria-label="ViewCube"
      onKeyDown={handleKey}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      className={['flex flex-col items-center gap-1.5', className ?? ''].join(' ')}
      // Extra padding so perspective-projected cube faces don't clip at
      // the canvas overflow-hidden boundary.
      style={{ padding: 8 }}
    >
      {/* Stage: drag here to orbit; click a face/corner to snap. */}
      <div
        data-testid="view-cube-stage"
        style={{ ...stageStyle, filter: 'drop-shadow(0 2px 8px rgba(0,0,0,0.20))' }}
        onPointerDown={handlePointerDown}
        onClickCapture={handleClickCapture}
      >
        <div style={cubeStyle} data-cube-stage="true">
          {FACES.map((face) => (
            <CubeFace
              key={face.id}
              face={face}
              onClick={() => emit({ kind: 'face', face: face.id })}
            />
          ))}
        </div>

        {/* Corner snap targets: only appear on hover. */}
        {TOP_CORNERS.map((c) => (
          <button
            key={c.id}
            type="button"
            onClick={() => emit({ kind: 'corner', corner: c.id })}
            aria-label={`Align camera to ${c.id}`}
            data-corner={c.id}
            style={{
              position: 'absolute',
              left: c.left,
              top: c.top,
              transform: 'translate(-50%, -50%)',
              width: 10,
              height: 10,
              borderRadius: 5,
              border: '1px solid var(--color-border)',
              background: 'var(--color-surface)',
              cursor: 'pointer',
              padding: 0,
              opacity: showChrome ? 0.6 : 0,
              transition: 'opacity 150ms',
            }}
          />
        ))}
      </div>

      {/* Compass + reset: fade in on hover only. */}
      <div
        style={{
          opacity: showChrome ? 1 : 0,
          transition: 'opacity 150ms',
          pointerEvents: showChrome ? 'auto' : 'none',
        }}
        className="flex items-center gap-1.5"
      >
        <Compass currentAzimuth={currentAzimuth} />
        <button
          type="button"
          onClick={() => {
            emit({ kind: 'home' });
            onHome?.();
          }}
          aria-label="Reset to default view"
          title="Click to reset camera"
          className="inline-flex h-4 w-4 items-center justify-center rounded text-muted hover:text-foreground"
        >
          <Icons.viewCubeReset size={11} aria-hidden="true" />
        </button>
      </div>
    </div>
  );
}

function CubeFace({ face, onClick }: { face: FaceDef; onClick: () => void }): JSX.Element {
  const bgColor =
    face.shade === 0
      ? 'var(--color-surface)'
      : `color-mix(in srgb, var(--color-surface) ${Math.round((1 - face.shade) * 100)}%, var(--color-foreground) ${Math.round(face.shade * 100)}%)`;

  const style: CSSProperties = {
    position: 'absolute',
    inset: 0,
    transform: face.transform,
    background: bgColor,
    border: '1px solid var(--color-border)',
    color: 'var(--color-foreground)',
    fontSize: 7,
    fontWeight: 600,
    letterSpacing: '0.1em',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    cursor: 'grab',
    backfaceVisibility: 'hidden',
    boxShadow: 'inset 0 0 0 1px color-mix(in srgb, var(--color-border) 40%, transparent)',
    userSelect: 'none',
    opacity: 0.9,
  };

  return (
    <button
      type="button"
      onClick={onClick}
      aria-label={`Align camera to ${face.id}`}
      data-face={face.id}
      style={style}
      className="hover:brightness-110"
    >
      {face.label}
    </button>
  );
}

function Compass({ currentAzimuth }: { currentAzimuth: number }): JSX.Element {
  const label = compassLabelFromAzimuth(currentAzimuth);
  return (
    <div
      role="img"
      aria-label={`Compass · north toward ${label}`}
      data-testid="view-cube-compass"
      data-cardinal={label}
      className="flex items-center gap-0.5 text-[10px] font-medium text-muted"
    >
      <span aria-hidden="true" className="opacity-50">⌖</span>
      <span>{label}</span>
    </div>
  );
}

import { type CSSProperties, type JSX, type KeyboardEvent, useCallback, useRef } from 'react';
import { Icons, ICON_SIZE } from '@bim-ai/ui';
import {
  isToolDisabled,
  paletteForMode,
  type ToolDisabledContext,
  type ToolId,
  type WorkspaceMode,
} from './toolRegistry';

/**
 * ToolPalette — spec §16.
 *
 * Top-floating, mode-aware tool group. Each button is 36 × 36 with the
 * lucide icon centered and the hotkey letter as a `--text-xs` superscript
 * bottom-right. `role="toolbar"` with arrow-key traversal between
 * buttons. Active tool gets `--color-accent` background; disabled tools
 * get 0.4 opacity and the disablement reason as the tooltip.
 *
 * The Tag subdropdown (`Tag ▾`) is exposed as a separate trailing
 * button; clicking it dispatches `onTagSubmenu()` so the consumer can
 * mount the §16.5 menu.
 */

export interface ToolPaletteProps {
  mode: WorkspaceMode;
  activeTool: ToolId;
  onToolSelect: (id: ToolId) => void;
  /** Tool-disablement context (wall / floor / selection presence). */
  disabledContext: ToolDisabledContext;
  /** Tag dropdown trigger; the menu itself is rendered by the parent. */
  onTagSubmenu?: () => void;
}

export function ToolPalette({
  mode,
  activeTool,
  onToolSelect,
  disabledContext,
  onTagSubmenu,
}: ToolPaletteProps): JSX.Element {
  const tools = paletteForMode(mode);
  const refs = useRef<Map<ToolId, HTMLButtonElement>>(new Map());
  const setRef = useCallback(
    (id: ToolId) => (el: HTMLButtonElement | null) => {
      if (el) refs.current.set(id, el);
      else refs.current.delete(id);
    },
    [],
  );

  const handleKey = useCallback(
    (event: KeyboardEvent<HTMLDivElement>) => {
      if (event.key !== 'ArrowRight' && event.key !== 'ArrowLeft') return;
      const idx = tools.findIndex((t) => t.id === activeTool);
      if (idx < 0) return;
      const delta = event.key === 'ArrowRight' ? 1 : -1;
      const next = tools[(idx + delta + tools.length) % tools.length]!;
      event.preventDefault();
      onToolSelect(next.id);
      refs.current.get(next.id)?.focus();
    },
    [activeTool, onToolSelect, tools],
  );

  return (
    <div
      role="toolbar"
      aria-label="Drawing tools"
      data-testid="tool-palette"
      onKeyDown={handleKey}
      style={paletteStyle}
      className="flex items-center gap-0.5 rounded-md border border-border bg-background/95 px-1.5 py-1.5 shadow-elev-2 backdrop-blur-sm"
    >
      {tools.map((tool) => {
        const Icon = Icons[tool.icon]!;
        const enablement = isToolDisabled(tool.id, disabledContext);
        const isActive = tool.id === activeTool;
        return (
          <button
            key={tool.id}
            ref={setRef(tool.id)}
            type="button"
            aria-label={`${tool.label} (${tool.hotkey})`}
            aria-pressed={isActive}
            aria-keyshortcuts={tool.hotkey}
            aria-disabled={enablement.disabled}
            tabIndex={isActive ? 0 : -1}
            disabled={enablement.disabled}
            title={enablement.disabled ? enablement.reason : tool.tooltip}
            data-tool={tool.id}
            data-active={isActive ? 'true' : 'false'}
            onClick={() => {
              if (enablement.disabled) return;
              if (tool.id === 'tag') onTagSubmenu?.();
              else onToolSelect(tool.id);
            }}
            className={[
              'relative inline-flex h-8 w-8 items-center justify-center rounded transition-colors',
              isActive
                ? 'bg-accent text-accent-foreground shadow-sm'
                : 'text-muted hover:bg-surface hover:text-foreground',
              enablement.disabled ? 'opacity-40' : '',
            ].join(' ')}
          >
            <Icon size={16} aria-hidden="true" />
            <span
              aria-hidden="true"
              className="pointer-events-none absolute bottom-0.5 right-0.5 text-[8px] font-medium opacity-60 tabular-nums"
            >
              {tool.hotkey.replace('Shift+', '⇧')}
            </span>
          </button>
        );
      })}
    </div>
  );
}

const paletteStyle: CSSProperties = {
  // Top-center floating per §16; absolute positioning is left to caller.
  zIndex: 10,
};

import { type JSX, useEffect, useRef, useState } from 'react';
import { ICON_SIZE, Icons, type LucideLikeIcon } from '@bim-ai/ui';

import { TAB_KIND_LABEL, type TabKind, type ViewTab } from './tabsModel';

/**
 * TabBar — spec §11.3.
 *
 * Horizontal strip of open-view tabs sitting between the TopBar and
 * the canvas. Each tab carries a `kind` icon, a truncated label, and a
 * close ✕ button. Trailing `+` opens an "add view" popover.
 */

const TAB_KIND_ICON: Record<TabKind, LucideLikeIcon> = {
  plan: Icons.floor!,
  '3d': Icons.family!, // Component (cube) — used for 3D views
  'plan-3d': Icons.floor!,
  section: Icons.section!,
  sheet: Icons.sheet!,
  schedule: Icons.schedule!,
  agent: Icons.agent!,
};

export interface TabBarProps {
  tabs: ViewTab[];
  activeId: string | null;
  onActivate: (id: string) => void;
  onClose: (id: string) => void;
  /** Called when the user clicks a "+ {kind}" entry in the trailing
   * popover. The kind names a target the host should resolve (e.g.
   * "+ Plan" → open the active level as a tab). */
  onAdd?: (kind: TabKind) => void;
  /** Called when the user drags a tab to a new position. The host
   * should run the `reorderTab` reducer with the same indices. */
  onReorder?: (fromIdx: number, toIdx: number) => void;
}

const ADDABLE_KINDS: TabKind[] = ['plan', '3d', 'plan-3d', 'section', 'sheet', 'schedule', 'agent'];

export function TabBar({
  tabs,
  activeId,
  onActivate,
  onClose,
  onAdd,
  onReorder,
}: TabBarProps): JSX.Element {
  const [popoverOpen, setPopoverOpen] = useState(false);
  const [dragSrc, setDragSrc] = useState<number | null>(null);
  const [dragOverIdx, setDragOverIdx] = useState<number | null>(null);
  const popoverRef = useRef<HTMLDivElement | null>(null);

  // Click-outside closes the popover.
  useEffect(() => {
    if (!popoverOpen) return;
    const onDoc = (e: MouseEvent): void => {
      if (popoverRef.current && !popoverRef.current.contains(e.target as Node)) {
        setPopoverOpen(false);
      }
    };
    document.addEventListener('mousedown', onDoc);
    return () => document.removeEventListener('mousedown', onDoc);
  }, [popoverOpen]);

  return (
    <div
      role="tablist"
      aria-label="Open views"
      data-testid="view-tabs"
      className="flex items-end gap-0.5 border-b border-border bg-surface px-2 pt-1.5"
      style={{ height: 38 }}
    >
      {tabs.length === 0 ? (
        <div className="px-2 pb-1.5 text-xs text-muted">No views open</div>
      ) : null}
      {tabs.map((tab, idx) => {
        const Icon = TAB_KIND_ICON[tab.kind] ?? Icons.floor!;
        const isActive = tab.id === activeId;
        const isDragOver = dragOverIdx === idx && dragSrc !== null && dragSrc !== idx;
        const truncated = tab.label.length > 22 ? tab.label.slice(0, 21) + '…' : tab.label;
        return (
          <div
            key={tab.id}
            role="tab"
            aria-selected={isActive}
            data-tab-id={tab.id}
            data-tab-index={idx}
            data-active={isActive ? 'true' : 'false'}
            data-drag-over={isDragOver ? 'true' : 'false'}
            draggable={Boolean(onReorder)}
            onDragStart={(e) => {
              if (!onReorder) return;
              setDragSrc(idx);
              e.dataTransfer.effectAllowed = 'move';
              try {
                e.dataTransfer.setData('text/plain', String(idx));
              } catch {
                /* some browsers throw on setData inside synthetic events */
              }
            }}
            onDragOver={(e) => {
              if (!onReorder || dragSrc === null) return;
              e.preventDefault();
              e.dataTransfer.dropEffect = 'move';
              if (dragOverIdx !== idx) setDragOverIdx(idx);
            }}
            onDragLeave={() => {
              if (dragOverIdx === idx) setDragOverIdx(null);
            }}
            onDrop={(e) => {
              if (!onReorder || dragSrc === null) return;
              e.preventDefault();
              if (dragSrc !== idx) onReorder(dragSrc, idx);
              setDragSrc(null);
              setDragOverIdx(null);
            }}
            onDragEnd={() => {
              setDragSrc(null);
              setDragOverIdx(null);
            }}
            className={[
              'group flex items-center gap-1.5 rounded-t-md border border-b-0 px-3 py-1.5 text-xs font-medium transition-colors',
              isActive
                ? 'border-border bg-background text-foreground shadow-sm'
                : 'border-transparent text-muted hover:bg-background/60 hover:text-foreground',
              isDragOver ? 'ring-2 ring-accent ring-offset-0' : '',
            ].join(' ')}
            style={
              isActive
                ? { boxShadow: 'inset 0 -2px 0 0 var(--color-accent), 0 -1px 3px 0 rgba(0,0,0,0.04)' }
                : undefined
            }
          >
            <button
              type="button"
              onClick={() => onActivate(tab.id)}
              aria-label={`${TAB_KIND_LABEL[tab.kind]}: ${tab.label}`}
              className="flex items-center gap-1.5 rounded"
              title={`${TAB_KIND_LABEL[tab.kind]} · ${tab.label}`}
              data-testid={`tab-activate-${tab.id}`}
            >
              <Icon
                size={13}
                aria-hidden="true"
                className={isActive ? 'text-accent' : 'text-muted'}
              />
              <span className="whitespace-nowrap">{truncated}</span>
            </button>
            <button
              type="button"
              onClick={(e) => {
                e.stopPropagation();
                onClose(tab.id);
              }}
              aria-label={`Close ${tab.label}`}
              data-testid={`tab-close-${tab.id}`}
              className={[
                'rounded p-0.5 hover:bg-surface-strong',
                isActive ? 'opacity-50 hover:opacity-100' : 'opacity-0 group-hover:opacity-50 group-hover:hover:opacity-100',
              ].join(' ')}
            >
              <Icons.close size={11} aria-hidden="true" />
            </button>
          </div>
        );
      })}
      <div className="relative ml-1" ref={popoverRef}>
        <button
          type="button"
          onClick={() => setPopoverOpen((v) => !v)}
          aria-label="Open new view"
          data-testid="tab-add-button"
          className="flex h-6 w-6 items-center justify-center rounded text-muted hover:bg-surface-strong hover:text-foreground"
          style={{ fontSize: 16, lineHeight: 1 }}
        >
          +
        </button>
        {popoverOpen ? (
          <div
            role="menu"
            data-testid="tab-add-popover"
            className="absolute left-0 top-full z-30 mt-1 flex min-w-[180px] flex-col rounded-md border border-border bg-surface shadow-elev-2"
          >
            {ADDABLE_KINDS.map((kind) => {
              const Icon = TAB_KIND_ICON[kind];
              return (
                <button
                  key={kind}
                  type="button"
                  role="menuitem"
                  onClick={() => {
                    setPopoverOpen(false);
                    onAdd?.(kind);
                  }}
                  className="flex items-center gap-2 px-3 py-1.5 text-left text-xs text-foreground hover:bg-surface-strong"
                  data-testid={`tab-add-${kind}`}
                >
                  <Icon size={ICON_SIZE.chrome} aria-hidden="true" />
                  <span>+ {TAB_KIND_LABEL[kind]}</span>
                </button>
              );
            })}
          </div>
        ) : null}
      </div>
    </div>
  );
}

